"""
MKT Original Language Commentary — 2 Chronicles chapters 9–12
Run: python3 scripts/zc-original-2chronicles-9-12.py

Ch9:  Queen of Sheba (ḥîdōt = riddles; lĕnassōt = test/prove; ʾašrê = blessed;
      ʾalmugîm wood hapax; ẑāhāḇ šāḥûṭ = hammered gold; ḥōzeh for prophetic sources)
Ch10: Kingdom divided (ʿōl = yoke; qāšāh = make heavy; nĕsibāh = turn from God;
      mārad = rebel; yĕlāḏîm = young men as inexperienced; dābār ṭôḇ = good word)
Ch11: Rehoboam fortifies Judah (kānaʿ = humble; nāgîḏ = prince-designate; dāraš = seek;
      śĕʿîrîm = goat-demons; the mass Levitical migration south)
Ch12: Shishak invasion and partial repentance (ʿāzaḇ/ʿāzaḇ talion; Niphal kānaʿ;
      hēkîn lĕḇāḇô = establish the heart; sukkiyyîm = Sukkites, hapax OT)

Key decisions:
- ḥîdōt (9:1): "hard questions" = riddles/enigmas, same root as Samson's riddle (Judg 14:12-18)
- nĕsibāh (10:15): "turn of events" signals the Chronicler's explicit divine-causation gloss
- kānaʿ (12:6): Niphal self-abasement — the Chronicler's signature repentance verb (cf. 2 Chr 7:14)
- hēkîn lĕḇāḇô (12:14): the "prepared/established heart" idiom as the standard for Davidic fidelity
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON2_ORIGINAL = {
  "9": {
    "1": "<p><strong>ḥ&icirc;ḏ&ocirc;t</strong> &mdash; &lsquo;hard questions&rsquo; (ESV), lit. <em>riddles</em> or <em>enigmas</em>. The root <em>ḥûḏ</em> produces <em>ḥîḏāh</em>: a dark, indirect saying requiring interpretive effort. The identical word is used for Samson&rsquo;s riddle at the wedding feast (Judg 14:12&ndash;18) and in Num 12:8 where YHWH speaks with Moses &lsquo;mouth to mouth, clearly, and not in riddles&rsquo; (<em>wĕlōʾ bĕḥîḏōt</em>). For Solomon to be tested by riddles frames wisdom as a contest requiring deep discernment, not surface knowledge. The queen travels to Jerusalem &lsquo;to test him with riddles&rsquo; (<em>lĕnassōt bĕḥîḏōt</em>): <em>nāsāh</em> (Piel: to test, prove) is the same root as YHWH testing Abraham in Gen 22:1. A human queen plays, in miniature, the role of divine examiner.</p>",
    "2": "<p>Solomon told her all her words (<em>wayyagg&ecirc;ḏ-lāh šĕlōmōh ʾet-kol-dĕḇārêhā</em>). <em>Higgîd</em> (Hiphil of <em>nāgaḏ</em>) = to declare, make known, tell. The emphasis is not that Solomon answered questions but that he <em>told</em> all her words back to her &mdash; she did not need to explain; wisdom anticipated her questions. &lsquo;There was nothing hidden from Solomon that he did not tell her&rsquo; (<em>lōʾ-nĕʿlam miššĕlōmōh dābār</em>) &mdash; <em>nāʿal</em> (Niphal) = to be concealed. Wisdom as total transparency: nothing is hidden from the wise.</p>",
    "3": "<p>The queen saw (<em>watteʾreʾ</em>) the wisdom of Solomon (<em>ʾet-ḥokmāt šĕlōmōh</em>) and the house he had built. The combination of <em>ḥokmāh</em> (wisdom, abstract) and <em>habbayit</em> (the house, concrete) signals that in Chronicles, wisdom is not theoretical intelligence but the capacity that produces magnificent ordered reality &mdash; embodied most fully in the temple structure itself. The queen is a witness who sees wisdom&rsquo;s material fruit.</p>",
    "4": "<p>&lsquo;The food of his table, the seating of his servants, the attendance of his ministers&rsquo; (<em>maʾăkal šulḥānô ûmôšaḇ ʿăḇādāyw ûmaʿămaḏ mĕšārĕtāyw</em>). Three parallel noun phrases (<em>maʾăkal / môšaḇ / maʿămaḏ</em>) describe the ordered infrastructure of wisdom&rsquo;s reign. <em>maʿămaḏ</em> (standing place, post) is used for the Levitical posts in the temple (cf. 2 Chr 35:2, 10, 15). The queen&rsquo;s catalog ends with &lsquo;his burnt offerings that he offered in the house of YHWH&rsquo; &mdash; the climax. Solomon&rsquo;s administration culminates in worship, not statecraft.</p>",
    "5": "<p>&lsquo;She said to the king: True was the word (<em>ʾemet hāyāh haddāḇār</em>) I heard in my land about your deeds and your wisdom.&rsquo; <em>ʾemet</em> (truth, faithfulness) is used as a predicate: the report is true. <em>lōʾ heʾĕmantî lĕḏiḇrêhem</em> &mdash; &lsquo;I did not believe their words&rsquo; (<em>heʾĕmîn</em> = Hiphil of <em>ʾāman</em>, the root of <em>ʾāmēn</em>: to trust, believe). The queen&rsquo;s confession is an epistemological moment: hearing was insufficient; seeing produced certainty. Reports (<em>dĕḇārîm</em>) about wisdom cannot substitute for wisdom&rsquo;s presence.</p>",
    "6": "<p>&lsquo;Half the greatness of your wisdom was not told me (<em>lōʾ-huggadlî ḥăṣî rōḇ ḥokmātĕḵā</em>).&rsquo; <em>ḥăṣî</em> = half; <em>rōḇ</em> = abundance, greatness. The formulation is superlative: even the full report she had received conveyed only half the reality. <em>yāsaptā ʿal-haššĕmûʿāh</em> = &lsquo;you have surpassed the report&rsquo; (Hiphil of <em>yāsap</em>: to add/surpass). The queen&rsquo;s speech is a formal testimony to wisdom exceeding reputation &mdash; a motif that the Chronicler uses to establish Solomon as the apex of human wisdom.</p>",
    "7": "<p><strong>ʾašrê ʾănāšêḵā</strong> &mdash; &lsquo;Blessed are your men!&rsquo; <em>ʾašrê</em> is the plural construct noun of happiness/blessedness &mdash; the same word that opens Ps 1:1 (&lsquo;Blessed is the man&rsquo;) and appears throughout the Psalter (Ps 32:1-2; 33:12; etc.). The beatitude formula applied to Solomon&rsquo;s servants: those who &lsquo;stand before you continually and hear your wisdom&rsquo; (<em>ʿōmĕḏîm lĕpānêḵā tāmîḏ wĕšōmĕʿîm ʾet-ḥokmātĕḵā</em>). <em>tāmîḏ</em> (continually, the adverb of the daily offering) elevates their proximity from courtly privilege to liturgical status: they live in the daily rhythm of wisdom&rsquo;s presence.</p>",
    "8": "<p>&lsquo;Blessed be YHWH your God who delighted in you (<em>ḥāpēṣ bĕḵā</em>) to set you on his throne as king.&rsquo; <em>ḥāpēṣ</em> (Qal perfect: to delight in, take pleasure in) is the root of <em>ḥēpeṣ</em> (delight, pleasure; cf. Isa 53:10 &lsquo;it pleased YHWH to crush him&rsquo;). The queen articulates the Chronicler&rsquo;s core theology: Solomonic kingship derives not from Davidic genetics alone but from <em>divine delight</em>. &lsquo;Because your God loved Israel (<em>ʾāhēḇ YHWH ʾet-yiśrāʾēl</em>) to establish them forever (<em>lĕhaʿămîḏô lĕʿōlām</em>), he made you king over them to do justice and righteousness (<em>mišpāṭ ûṣĕḏāqāh</em>).&rsquo; The purpose of kingship is <em>mišpāṭ</em> (justice) and <em>ṣĕḏāqāh</em> (righteousness) &mdash; the two pillars of Davidic rule throughout the prophets (Isa 9:7; 11:4; Jer 23:5).</p>",
    "9": "<p>The queen gives (<em>wattitten</em>) Solomon 120 talents of gold (<em>mēʾāh wĕʿeśrîm kikkār zāhāḇ</em>), spices (<em>bĕśāmîm</em>) in great abundance, and precious stones. <em>kikkār</em> (talent) = the standard large weight unit (c. 34 kg / 75 lbs). 120 talents of gold represents approximately 4,000 kg &mdash; an enormous diplomatic gift. <em>bĕśāmîm</em> (spices) &mdash; the same word used for the incense ingredients of the tabernacle (Exod 25:6; 35:8). The queen&rsquo;s gift vocabulary evokes the materials of worship.</p>",
    "10": "<p>The servants of Huram (<em>ʿaḇḏê ḥûrām</em>) and the servants of Solomon who brought gold from Ophir also brought <em>ʿăṣê ʾalmugîm</em> (algum wood) and precious stones. <em>ʾalmugîm</em> is a hapax (unique form) in Chronicles; the parallel in 1 Kgs 10:11 reads <em>ʾalgummîm</em> &mdash; a metathesis (letter transposition) between the two traditions. The wood is likely sandalwood (<em>Pterocarpus santalinus</em>), used for temple musical instruments and the palace balustrade. Its rarity marks it as exotic tribute material.</p>",
    "11": "<p>Solomon made from the <em>ʿăṣê ʾalmugîm</em> terraces (<em>mĕsillôt</em>) for the house of YHWH and the king&rsquo;s house, and lyres (<em>kinnōrôt</em>) and harps (<em>nĕḇālîm</em>) for the singers. <em>mĕsillôt</em> is a cognate of <em>sōlal</em> (to cast up a road/ramp) &mdash; probably a staircase balustrade or ramp inlaid with the exotic wood. The narrator comments: &lsquo;none like them had been seen before in the land of Judah&rsquo; (<em>wĕlōʾ nirʾû ḵēhem lĕpānîm bĕʾereṣ yĕhûḏāh</em>) &mdash; the superlative uniqueness formula.</p>",
    "12": "<p>Solomon gave (<em>nātan</em>) the queen of Sheba all she desired (<em>kol-ḥepṣāh</em>). <em>ḥēpeṣ</em> (desire, pleasure) &mdash; the same root as &lsquo;delighted&rsquo; in v8 (&lsquo;YHWH delighted in you&rsquo;). What YHWH delights in becomes the standard of what the queen desires; the word link is probably intentional. &lsquo;More than what she had brought to the king&rsquo; (<em>mĕlĕḇad ʾăšer-hēḇîʾāh ʾel-hammelek</em>) &mdash; Solomon gives back more than he receives, the hallmark of Solomonic abundance.</p>",
    "13": "<p>&lsquo;The weight of gold (<em>mišqal hazzāhāḇ</em>) that came to Solomon in one year was 666 talents (<em>šeš mēʾôt šiššîm wĕšēš kikkār</em>).&rsquo; The number 666 in Chronicles is a fiscal calculation, not a symbolic one (contrast Rev 13:18). As an annual income figure, 666 talents ≈ 22,700 kg of gold, representing the apex of ancient Near Eastern wealth. The accumulation of gold is presented as fulfillment of the covenant blessing (Deut 28:12).</p>",
    "14": "<p>&lsquo;Besides what the merchants and traders brought&rsquo; (<em>lĕḇaḏ mēʾandê hattāgārîm wĕharrōḵĕlîm mĕḇîʾîm</em>). <em>tāgārîm</em> = merchants (from <em>sāgar</em>/Aramaic cognate, one who trades). <em>rōḵĕlîm</em> = traders, peddlers (cf. Ezek 27:13, 17, 22 for the same word in the Tyre trade oracle). &lsquo;All the kings of Arabia (<em>malkê ʿăraḇ</em>) and governors of the land (<em>paḥôt hāʾāreṣ</em>)&rsquo; also brought tribute. <em>paḥôt</em> (plural of <em>pehāh</em>) = governor, a term that becomes common for Persian-period administrators; its appearance here in a Solomonic context may be anachronistic coloring or may reflect a genuine pre-exilic title.</p>",
    "15": "<p>Solomon made 200 large shields (<em>māginnê zāhāḇ šāḥûṭ</em>) of beaten gold. <em>šāḥûṭ</em> (Qal passive participle of <em>šāḥaṭ</em>) = hammered, beaten out; gold worked by hammering rather than casting. Each shield used 600 shekels of gold (<em>šēš-mēʾôt zāhāḇ yāʿăleh ʿal-hammāgēn hāʾeḥāḏ</em>). <em>māgēn</em> (round shield) vs. <em>ṣinnāh</em> (v16, the large rectangular body shield) &mdash; the two types of military shield represent different functional designs; their ceremonial gold versions were housed in the House of the Forest of Lebanon.</p>",
    "16": "<p>Three hundred small shields (<em>šĕlōšet mēʾôt mēginnîm</em>) of beaten gold; 300 shekels of gold each. &lsquo;The king put them in the House of the Forest of Lebanon (<em>bêt yaʿar hallĕḇānôn</em>).&rsquo; The House of the Forest of Lebanon (1 Kgs 7:2-5) was Solomon&rsquo;s large armory/treasury building, named for its cedar pillars suggesting a cedar forest interior. Gold shields in an armory function as treasury reserves and royal display items simultaneously, converting military symbolism into wealth storage.</p>",
    "17": "<p>&lsquo;The king made a great ivory throne (<em>kissēʾ-šēn gāḏôl</em>) and overlaid it with pure gold (<em>wayyĕṣappēhû zāhāḇ ṭāhôr</em>).&rsquo; <em>kissēʾ</em> (throne) is the seat of royal judgment. <em>šēn</em> (ivory, lit. tooth) = elephant tusk ivory. <em>zāhāḇ ṭāhôr</em> (pure gold) is the technical term for the highest-grade gold, identical to the term used for the most sacred temple furnishings (the ark&rsquo;s overlay, the lampstand, the mercy seat &mdash; Exod 25:11, 17, 31). The throne&rsquo;s gold classification links Solomon&rsquo;s judicial seat to the holy-of-holies furniture.</p>",
    "18": "<p>&lsquo;The throne had six steps (<em>šēš maʿălôt</em>).&rsquo; <em>maʿălôt</em> = steps, ascents (same as the <em>maʿălôt</em> of Ps 120&ndash;134, the Psalms of Ascents). A golden footstool (<em>kěḇeš zāhāḇ</em>) was attached to the throne. The footstool of the king&rsquo;s throne echoes the ark-as-footstool of YHWH (Ps 99:5; 132:7; 1 Chr 28:2 where David calls the ark &lsquo;the footstool of our God&rsquo;). The throne geometry overlaps with temple geometry.</p>",
    "19": "<p>Twelve lions (<em>šĕnêm ʿāśār ʾărāyôt</em>) stood on the six steps, one on each side of each step. <em>ʾaryēh</em> (lion) is the royal animal of Judah (Gen 49:9; Rev 5:5). Twelve lions = the twelve tribes under royal-Judahite authority. The detail &lsquo;nothing like it was made for any kingdom&rsquo; (<em>lōʾ-nāʿăśāh kēn lĕḵol-mamlāḵāh</em>) is the uniqueness formula applied to the entire construction, elevating Solomon&rsquo;s throne beyond all human precedent.</p>",
    "20": "<p>&lsquo;All the drinking vessels of King Solomon were gold (<em>zāhāḇ</em>), and all the vessels of the House of the Forest of Lebanon were pure gold; silver was not considered as anything (<em>hakkesep lōʾ nẹhšāḇ</em>) in the days of Solomon.&rsquo; <em>nẹhšāḇ</em> = counted, valued (Niphal of <em>ḥāšaḇ</em>: to reckon, compute). The statement is economic hyperbole communicating the superabundance of gold &mdash; silver has been demonetized by gold&rsquo;s abundance.</p>",
    "21": "<p>The king&rsquo;s ships (<em>ʾŏniyyôt</em>) went to Tarshish with the servants of Huram. Once every three years (<em>lĕšālōš šānîm ʾaḥat</em>) they returned carrying gold, silver, ivory (<em>šēn</em>), apes (<em>qōp&icirc;m</em>), and peacocks (<em>tûkkiyyîm</em>). <em>Tarshish</em> is generally identified with distant western Mediterranean ports (Tartessos in Spain?); <em>ʾŏniyyôt taršîš</em> may be a ship-type designation (ocean-going vessels) rather than exclusively ships going to Tarshish. <em>tûkkiyyîm</em> (peacocks) appears only here and in 1 Kgs 10:22; possibly an Egyptian or Indian loanword. The exotic cargo list signals the reaches of Solomonic trade networks.</p>",
    "22": "<p>&lsquo;King Solomon surpassed (<em>waygaḏḏēl</em>) all the kings of the earth in riches and wisdom.&rsquo; <em>waygaḏḏēl</em> (Hiphil of <em>gāḏal</em>: to make great, surpass) is the Chronicler&rsquo;s greatness-ascription formula. The dual surpassing (wealth <em>and</em> wisdom) ties the two strands of the chapter together: the Queen of Sheba witnessed both, and the narrator confirms both.</p>",
    "23": "<p>&lsquo;All the kings of the earth (<em>kōl-malkê hāʾāreṣ</em>) were seeking the face of Solomon (<em>mĕḇaqqĕšîm ʾet-pĕnê šĕlōmōh</em>) to hear his wisdom.&rsquo; <em>bāqaš pĕnê</em> (to seek the face of) is the idiom for seeking audience with a superior, frequently used of seeking YHWH&rsquo;s face (Ps 27:8; 2 Chr 7:14). Applied to Solomon, the phrase elevates him to a quasi-divine role: the nations who should seek YHWH&rsquo;s face are directed toward Solomon as his wisdom&rsquo;s embodiment. <em>kōl-malkê hāʾāreṣ</em> (all the kings of the earth) is the Chronicler&rsquo;s hyperbole for universal recognition.</p>",
    "24": "<p>Each brought his tribute (<em>minhāt&ocirc;w</em>): silver and gold vessels, clothing (<em>śalmôt</em>), weapons (<em>nešeq</em>), spices (<em>bĕśāmîm</em>), horses, and mules. <em>minhāh</em> in this context = gift/tribute (not the technical sacrificial grain offering, though the word is shared). The tribute list parallels the materials of temple construction, suggesting that the nations&rsquo; tribute to Solomon implicitly supports the temple economy.</p>",
    "25": "<p>Solomon had 4,000 stalls for horses and chariots (<em>ʾuryôt lassûsîm ûlammerkāḇôt</em>) and 12,000 horsemen. <em>ʾuryôt</em> = stalls (for horses/donkeys); the root may relate to light or feeding place. Kings counts 40,000 stalls (1 Kgs 4:26) &mdash; probably a scribal corruption in Kings; Chronicles&rsquo; 4,000 is consistent with the number of chariots deployed. The Chronicler placed them &lsquo;in the chariot cities (<em>ʿārê hāreḵeḇ</em>) and with the king in Jerusalem.&rsquo;</p>",
    "26": "<p>&lsquo;He was ruling (<em>mōšēl</em>) over all the kings from the River (<em>min-hannāhār</em>) to the land of the Philistines and to the border of Egypt.&rsquo; <em>hannāhār</em> = the (Euphrates) River; no specification needed because the Euphrates is <em>the</em> river in OT geography. The formula describes the territory of the Abrahamic promise (Gen 15:18: &lsquo;from the river of Egypt to the great river, the Euphrates&rsquo;). Solomon&rsquo;s kingdom is presented as fulfilling the land promise.</p>",
    "27": "<p>&lsquo;The king made silver as plentiful (<em>wăyitten hammelek ʾet-hakkesep bîrûšālāyim kāʾăḇānîm</em>) as stones in Jerusalem.&rsquo; The simile <em>kāʾăḇānîm</em> (like stones) compares silver to the most common, valueless substance in Judah&rsquo;s landscape. Cedar wood is similarly compared to the common sycamore-fig trees (<em>kaššiqmîm</em>) of the Shephelah. The comparison inverts scarcity and abundance: rare materials become as common as ordinary ones under Solomonic reign.</p>",
    "28": "<p>Horses were imported for Solomon from Egypt and from all lands (<em>mimmāṣrayim ûmikkol-hāʾărāṣôt</em>). The horse trade was one of Solomon&rsquo;s primary commercial activities (1 Kgs 10:28-29). Deut 17:16 warns the king not to &lsquo;multiply horses&rsquo; or return to Egypt for horses; the Chronicler reports the horse accumulation without the Deuteronomic critique that appears elsewhere. The tension between Deuteronomic law and Solomonic practice is left implicit.</p>",
    "29": "<p>&lsquo;The rest of the acts of Solomon, from first to last (<em>hāriʾšōnîm wĕhāʾaḥărōnîm</em>), are they not written in the records of Nathan the prophet (<em>ḏiḇrê nāṯān hannāḇîʾ</em>), the prophecy of Ahijah the Shilonite (<em>bĕniḇûʾāh ʾăḥiyyāh haššîlōnî</em>), and in the visions of Iddo the seer (<em>bĕḥăzôt yĕʿdô ḥōzeh</em>)?&rsquo; Three prophetic sources are named. <em>ḥōzeh</em> (seer, from <em>ḥāzāh</em>: to see visions) is distinct from <em>nāḇîʾ</em> (prophet): the seer receives visual revelation while the prophet speaks the divine word. Chronicles frequently cites prophetic histories as sources, constructing a hermeneutic where all of history is prophetically witnessed.</p>",
    "30": "<p>Solomon reigned in Jerusalem over all Israel for 40 years (<em>ʾarbaʿîm šānāh</em>). Forty years is also David&rsquo;s regnal length (1 Chr 29:27). The symmetry of father and son each reigning forty years frames the united monarchy as a perfectly balanced era. <em>mālak</em> (to reign, be king) is the regnal summary verb; its use here in the Qal perfect marks the completion of Solomon&rsquo;s reign as a narrative unit.</p>",
    "31": "<p>&lsquo;Solomon slept with his fathers (<em>wayyiškab šĕlōmōh ʿim-ʾăḇōtāyw</em>) and was buried in the city of his father David (<em>bĕʿîr dāwîḏ ʾāḇîw</em>).&rsquo; The royal death formula <em>wayyiškab ʿim-ʾăḇōtāyw</em> is the standard regnal conclusion. The burial in &lsquo;the city of his father David&rsquo; anchors Solomon in the Davidic dynastic tradition. Rehoboam his son reigned in his place (<em>wayyimlōḵ rĕḥaḇʿām bĕnô taḥtāyw</em>) &mdash; the succession formula, setting up ch10&rsquo;s crisis immediately.</p>"
  },
  "10": {
    "1": "<p>Rehoboam went to Shechem (<em>šĕḵem</em>) for all Israel had come to Shechem to make him king (<em>lĕhamlik ʾōtô</em>). Shechem, not Jerusalem: this is the politically charged northern assembly city &mdash; site of the covenant-renewal under Joshua (Josh 24:1), and now the site of the kingdom&rsquo;s fracture. The Chronicler does not explain why Shechem was chosen; the geography itself signals that the northern tribes are holding the coronation on their own terms, in their own territory.</p>",
    "2": "<p>Jeroboam son of Nebat was in Egypt (<em>bĕmiṣrayim</em>) where he had fled from King Solomon. When the people sent (<em>wayyi&scaron;lĕḥû</em>) for him, he came (<em>wayyāḇōʾ</em>). The Hiphil <em>wayyi&scaron;lĕḥû</em> (they sent) shows the people as active agents summoning Jeroboam, not him returning opportunistically. Egypt as refuge echoes Moses&rsquo;s flight to Midian and anticipates the later Egyptian exile. The return from Egypt will complete the narrative arc: what comes from Egypt disrupts the Davidic line.</p>",
    "3": "<p>&lsquo;Come to us and lighten the yoke (<em>qal mēʿōl ʾāḇîḵā</em>) of your father.&rsquo; <em>ʿōl</em> (yoke) is the servitude/oppression metaphor from the Exodus narrative (Lev 26:13: YHWH broke the &lsquo;bars of your yoke&rsquo;). The people&rsquo;s demand frames Solomon&rsquo;s labor as Pharaonic: the liberated nation finds itself under a new <em>ʿōl</em>. <em>qal</em> (make light, Hiphil of <em>qālal</em>) = reduce, lessen. The identical formula for oppressive labor appears in Exod 5:9 where Pharaoh commands &lsquo;let the work be heavy upon the men.&rsquo;</p>",
    "4": "<p>&lsquo;Your father made our yoke heavy (<em>hiḵḇîḏ ʾet-ʿullēnû</em>)&rsquo; &mdash; <em>kāḇēḏ</em> (Hiphil: to make heavy/burdensome). The root <em>k-b-d</em> also produces <em>kāḇôḏ</em> (glory, weight, honor). To &lsquo;make heavy&rsquo; the yoke is linguistically to make it glorious/weighty &mdash; a dark irony when the Davidic king&rsquo;s glory-weight falls on his people as burden. <em>waʿattāh hāqēl</em> = &lsquo;and now lighten it&rsquo; (<em>qal</em> imperative of <em>qālal</em>) &mdash; the people&rsquo;s appeal for relief is grammatically an imperative: command, not request.</p>",
    "5": "<p>Rehoboam says &lsquo;Come back to me in three days&rsquo; (<em>šûḇû ʾēlay ʿôḏ šĕlōšet yāmîm</em>). The three-day interval appears throughout the OT at pivotal moments (Gen 22:4; Exod 19:11; Josh 1:11; Jonah 1:17). The king needs three days to deliberate &mdash; but the decision is already structurally predetermined. <em>šûḇû</em> (return, come back) is the repentance verb; its use here for a political return is theologically neutral, but in Chronicles where <em>šûḇ</em> nearly always carries theological weight, the casual use foreshadows the spiritual failure that follows.</p>",
    "6": "<p>Rehoboam consulted (<em>wayyiwwāʿaṣ</em>) the elders (<em>zĕqēnîm</em>) who had served his father Solomon while he lived. <em>nāʿaṣ</em> (Niphal: to take counsel, deliberate) appears in the imperfect Niphal indicating ongoing consultation. The elders who &lsquo;stood before Solomon&rsquo; (<em>haʿōmĕḏîm lipnê šĕlōmōh</em>) use the liturgical standing-before vocabulary &mdash; <em>ʿāmaḏ lipnê</em> (to stand before) is the posture of attendant service. Their wisdom is tested wisdom; they have stood in the presence of the wisest king.</p>",
    "7": "<p>The elders advised: &lsquo;If you will be kind (<em>ṭôḇ</em>) to this people and please them and speak good words (<em>dĕḇārîm ṭôḇîm</em>) to them, they will be your servants forever (<em>laʿăḇādîm lĕḵā ḵol-hayyāmîm</em>).&rsquo; <em>ṭôḇ</em> (good) as the predicate of wise kingship: goodness is the quality that secures permanent loyalty. <em>dābār ṭôḇ</em> (good word) is also the idiom for a favorable oracle or decree. The elders frame royal wisdom as covenantal speech-act: a good word spoken creates an enduring relationship.</p>",
    "8": "<p>But Rehoboam forsook (<em>wayyaʿăzōḇ</em>) the counsel (<em>ʿēṣāh</em>) of the elders. <em>ʿāzaḇ</em> (to forsake, abandon) is the apostasy verb: the same word used when Israel forsakes YHWH (2 Chr 12:1; 15:2; 24:20; Judg 2:12). The king&rsquo;s political abandonment of the elders&rsquo; advice is linguistically identical to Israel&rsquo;s theological abandonment of God. He consulted the young men (<em>hayyĕlāḏîm</em>) who had grown up with him. <em>yĕlāḏîm</em> = boys, lads (diminutive-connoted); the word choice demeans their wisdom before they speak.</p>",
    "9": "<p>&lsquo;How do you advise me to answer this people?&rsquo; Rehoboam&rsquo;s question to the young men is formally identical to his question to the elders (v6), but the context has already signaled the answer he wants. The young men&rsquo;s response will mirror what he prefers rather than what is wise. The doubling of the consultation (elders / young men) is a literary device for moral contrast: wisdom rejected, folly chosen.</p>",
    "10": "<p>&lsquo;My little finger (<em>qaṭannî</em>) shall be thicker than my father&rsquo;s loins (<em>motnê ʾāḇî</em>).&rsquo; <em>qaṭannî</em> = my little one (from <em>qāṭān</em>, small); the young men&rsquo;s advice uses a body-part boast. <em>motnayim</em> (loins, lower back/hips) is the seat of strength in Hebrew idiom. The comparison makes Rehoboam&rsquo;s weakest point stronger than Solomon&rsquo;s strongest: a claim of absolute surpassing that is transparently absurd and reveals the young men&rsquo;s immaturity.</p>",
    "11": "<p>&lsquo;My father burdened you with a heavy yoke (<em>ʿōl kāḇēḏ</em>), and I will add to your yoke (<em>wĕʾănî ʾōsîp ʿal-ʿullĕkem</em>). My father chastised you with whips (<em>bĕšōṭîm</em>), but I will chastise you with scorpions (<em>bĕʿaqrabbîm</em>).&rsquo; <em>šōṭ</em> (whip) vs. <em>ʿaqraḇ</em> (scorpion): the escalation suggests a spiked lash or multi-tailed whip (Byzantine <em>scorpion</em> whip) rather than a literal arachnid. The speech represents an extreme violation of the Deuteronomic royal ideal (Deut 17:14-20), which required humility, not domination.</p>",
    "12": "<p>Jeroboam and all the people came to Rehoboam on the third day as the king had said (<em>kaʾăšer dibber hammelek lēmōr šûḇû ʾēlay bayyôm haššĕlîšî</em>). The return on the third day fulfills the appointment and triggers the decision. The faithfulness of the people in returning is contrasted with the king&rsquo;s faithlessness in his response. The parallel between &lsquo;third day&rsquo; appointments kept and covenants broken is a recurring OT irony.</p>",
    "13": "<p>Rehoboam answered them harshly (<em>qāšāh</em>). <em>qāšāh</em> (to be hard/harsh, Hiphil: to make hard) is the hardening vocabulary: the same root as Pharaoh&rsquo;s hardened heart in Exod 7:3; 13:15 and Israel&rsquo;s stiff-necked rebellion (Deut 9:6, <em>qĕšēh-ʿōrep</em>). Rehoboam&rsquo;s harsh answer enacts the Egyptian paradigm: the new Pharaoh refusing to release his laborers. The Exodus pattern runs backward under Davidic apostasy.</p>",
    "14": "<p>He spoke to them according to the counsel of the young men (<em>ʿăṣat hayyĕlāḏîm</em>): &lsquo;I will add to your yoke (<em>ʾōsîp ʿal-ʿullĕkem</em>) and I will chastise you with scorpions.&rsquo; The verbatim repetition of v11 confirms the choice. <em>yāsap</em> (Hiphil: to add) = to increase the burden. The Chronicler uses the same verb for the positive&ndash;&mdash;when YHWH adds to his people (2 Chr 25:9). Adding burden instead of blessing is the king&rsquo;s inversion of the divine pattern.</p>",
    "15": "<p>&lsquo;So the king did not listen to the people (<em>wĕlōʾ-šāmaʿ hammelek ʾel-hāʿām</em>), for the turn of events was from God (<em>kî-hāyĕtāh nĕsibāh mēʾim hāʾĕlōhîm</em>) that YHWH might establish his word.&rsquo; <em>nĕsibāh</em> (turn, turning point) is a rare noun (also 1 Kgs 12:15) from <em>sāḇaḇ</em> (to turn, surround). The Chronicler inserts an explicit theological gloss: the political disaster is YHWH&rsquo;s instrument to fulfill the prophetic word of Ahijah to Jeroboam (1 Kgs 11:31). Divine sovereignty operates <em>through</em> human folly.</p>",
    "16": "<p>&lsquo;What portion (<em>ḥēleq</em>) do we have in David? We have no inheritance (<em>naḥalāh</em>) in the son of Jesse!&rsquo; The schism cry uses covenant-land vocabulary: <em>ḥēleq</em> (portion, share in the land distribution) and <em>naḥalāh</em> (inheritance, the covenantal land right). The northern tribes declare themselves outside the Davidic covenant in the very terms of the land covenant. &lsquo;To your tents, O Israel!&rsquo; (<em>lĕʾōhāleḵā yiśrāʾēl</em>) &mdash; the dispersal formula, used when assemblies conclude (1 Sam 13:2; 2 Sam 20:1). The northern kingdom&rsquo;s founding act is a departure, not a founding assembly.</p>",
    "17": "<p>But Rehoboam reigned over the Israelites who were living in the cities of Judah. The Chronicler narrows the kingdom&rsquo;s scope explicitly: Rehoboam now rules only a remnant of the whole, geographically limited to Judah. This contraction prepares the Chronicler&rsquo;s theology that the true Israel is centered on Jerusalem and the Davidic dynasty &mdash; the northern kingdom is a political accident, not a legitimate covenant community.</p>",
    "18": "<p>King Rehoboam sent Hadoram (<em>hăḏōrām</em>) who was over the forced labor (<em>ʿal-hammas</em>). The people stoned him to death (<em>wayyirgĕmû-ḇô ʾaḇen wayyāmōt</em>). <em>sāqal/rāgam</em> (to stone) = the form of communal execution for grave offenses (Lev 24:16; Num 15:35). <em>hammas</em> (forced labor, corvée) is the taxation system that provoked the crisis; sending the official responsible for it first is either a miscalculation or a deliberate provocation. The stoning is the northern rejection of the entire administrative structure of Solomon&rsquo;s kingdom.</p>",
    "19": "<p>&lsquo;And Israel has been in rebellion (<em>māraḏ</em>) against the house of David to this day (<em>ʿaḏ hayyôm hazzeh</em>).&rsquo; <em>māraḏ</em> (to rebel) is the political-theological term for covenant disloyalty (Josh 22:16&ndash;19; Num 14:9). &lsquo;To this day&rsquo; (<em>ʿaḏ hayyôm hazzeh</em>) is the Chronicler&rsquo;s closing editorial marker, noting that the division persists into the narrator&rsquo;s own time. The northern rebellion is not merely historical: it is the ongoing condition of a community that has abandoned the Davidic covenant.</p>"
  },
  "11": {
    "1": "<p>Rehoboam came to Jerusalem and assembled (<em>wayyaqhēl</em>) the house of Judah and Benjamin &mdash; 180,000 <em>baḥûrê milḥāmāh</em> (chosen men of war). <em>bāḥar</em> (to choose, select) produces <em>bāḥûr</em> (chosen man, prime fighter). <em>wayyaqhēl</em> (Hiphil of <em>qāhal</em>: to assemble, convoke) is the vocabulary of the sacred assembly &mdash; the same word used for Moses assembling Israel at Sinai (Exod 35:1) and Solomon assembling Israel for the temple dedication (2 Chr 5:2). Rehoboam&rsquo;s military assembly is described in the language of covenant assembly, underscoring the theological stakes of the civil war he intends to wage.</p>",
    "2": "<p>The word of YHWH came (<em>wayhî dĕḇar-YHWH ʾel-šĕmaʿyāh</em>) to Shemaiah the man of God (<em>ʾîš hāʾĕlōhîm</em>). <em>ʾîš hāʾĕlōhîm</em> (man of God) is the fixed prophetic title (also used of Moses in 1 Chr 23:14, Elijah in 2 Kgs 1:9&ndash;13, and many others). Shemaiah&rsquo;s name (<em>šāmaʿ</em> + <em>yāh</em>) = &lsquo;YHWH has heard&rsquo; &mdash; the prophet who hears YHWH&rsquo;s word has a name that encodes YHWH&rsquo;s receptiveness. A divine hearing-name mediates a divine word about not fighting.</p>",
    "3": "<p>&lsquo;Speak to Rehoboam son of Solomon, king of Judah, and to all Israel in Judah and Benjamin.&rsquo; The address &lsquo;all Israel in Judah and Benjamin&rsquo; is the Chronicler&rsquo;s consistent claim: the true Israel is constituted by those who remain faithful to the Davidic-temple arrangement, not by the northern numerical majority. The two southern tribes plus the Levites and the faithful who migrate south = the remnant Israel of the Chronicler&rsquo;s theology.</p>",
    "4": "<p>&lsquo;Thus says YHWH: You shall not go up or fight against your brothers (<em>lōʾ-taʿălû wĕlōʾ-tillaḥămû ʿim-ʾăḥêkem</em>). Return every man to his house, for this thing is from me (<em>mēʾittî nĕhyĕtāh haddāḇār hazzeh</em>).&rsquo; <em>mēʾittî</em> (from me) + <em>nĕhyĕtāh</em> (has happened, Niphal of <em>hāyāh</em>) = the Chronicler&rsquo;s divine-causation formula, parallel to 10:15. YHWH directly claims authorship of the division. The warriors obey (<em>wayyišmĕʿû</em>): for once, the king and army heed the prophetic word.</p>",
    "5": "<p>Rehoboam lived (<em>wayyēšeḇ</em>) in Jerusalem and built (<em>wayyiḇen</em>) fortified cities (<em>ʿārê māṣôr</em>) in Judah. <em>māṣôr</em> (fortress, siege defense) from <em>ṣûr</em> (to besiege, confine). The shift from attempted military reconquest (vv1-4) to defensive fortification marks Rehoboam&rsquo;s strategic adjustment. The Chronicler presents this as legitimate royal activity &mdash; building, rather than fighting &mdash; appropriate to the chastened king who listened to the prophet.</p>",
    "6": "<p>He built Bethlehem (<em>bêt-leḥem</em>), Etam, Tekoa (<em>tĕqôaʿ</em>). Bethlehem is &lsquo;house of bread&rsquo; (food production city). Tekoa is the home of the prophet Amos (Amos 1:1) and of the wise woman of 2 Sam 14. The specific city selection in the list follows a geographic logic (from Jerusalem southward into the Shephelah and Negev), representing the full defensive perimeter of Judah.</p>",
    "7": "<p>Beth-zur (<em>bêt-ṣûr</em>), Soco (<em>śōkôh</em>), Adullam (<em>ʿădullām</em>). Beth-zur = house of rock/strength; Adullam = the site of David&rsquo;s cave refuge (1 Sam 22:1) &mdash; a location already associated with royal protection in extremity. The cities of the Shephelah control the western approaches into Judah from the coastal plain.</p>",
    "8": "<p>Gath (<em>gat</em>), Mareshah (<em>mārēšāh</em>), Ziph (<em>zîp</em>). Gath = the former Philistine city; its fortification by Rehoboam signals the extension of Judahite control over historically Philistine territory. Mareshah features prominently later (2 Chr 14:9-10 = the battle against Zerah the Cushite). The cities represent frontier defense of the western and southwestern borders.</p>",
    "9": "<p>Adoraim (<em>ʾăḏôrāyim</em>), Lachish (<em>lāḵîš</em>), Azekah (<em>ʿăzēqāh</em>). Lachish is the most significant fortified city in the list &mdash; a major administrative and military center that Assyria would besiege in 701 BC (2 Chr 32:9; Isa 36:2; the Lachish reliefs of Sennacherib). Azekah is also significant (Jer 34:7). The Chronicler&rsquo;s list anticipates subsequent military geography.</p>",
    "10": "<p>Zorah (<em>ṣorʿāh</em>), Aijalon (<em>ʾayyālôn</em>), Hebron (<em>ḥeḇrôn</em>) &mdash; which were in Judah and Benjamin, as fortified cities. Zorah is Samson&rsquo;s hometown (Judg 13:2). Aijalon is where the sun stood still (Josh 10:12). Hebron is the original Davidic capital (2 Sam 2:1-4). The list of fortified cities includes places of earlier covenant memory, suggesting that Rehoboam is not merely building strategically but reclaiming the full geographic inheritance of the Davidic covenant.</p>",
    "11": "<p>He reinforced (<em>wayyĕḥazzēq</em>) the strongholds and put commanders (<em>nĕgîḏîm</em>) in them, with food stores, oil, and wine. <em>ḥāzaq</em> (Piel: to strengthen, reinforce) is the Chronicler&rsquo;s characteristic word for consolidating what is threatened. <em>nāgîḏ</em> (prince, leader) is the term used for Saul&rsquo;s designation (1 Sam 9:16) and for the leaders of the northern migration in this chapter (v22). The word signals royal delegation of authority in the defensive network.</p>",
    "12": "<p>In every city, shields (<em>māginnîm</em>) and spears (<em>ḥănîṯîm</em>) were placed, and he made them very strong (<em>wayyĕḥazzĕqēm lĕmĕʾōḏ</em>). Rehoboam held Judah and Benjamin. <em>lĕmĕʾōḏ</em> (very much, exceedingly) as an intensifier. The physical fortification list (cities, commanders, provisions, weapons) is the Chronicler&rsquo;s portrait of a king who, after the prophetic chastening, channels his energy into legitimate defense rather than fratricidal civil war.</p>",
    "13": "<p>The priests and Levites who were in all Israel (<em>kol-yiśrāʾēl</em>) presented themselves to Rehoboam from all their territories. <em>hityaṣṣĕḇû ʿālāyw</em> (they stationed themselves / presented themselves to him) &mdash; the Hithpael of <em>yāṣaḇ</em> (reflexive: to take one&rsquo;s stand, present oneself). This verse introduces the great Levitical migration south. The Chronicler&rsquo;s point: the legitimate cultic order cannot function in the north under Jeroboam&rsquo;s system and therefore abandons it.</p>",
    "14": "<p>The Levites left their pasturelands (<em>migrĕšêhem</em>) and their property (<em>ʾăḥuzzātām</em>) and came to Judah and Jerusalem. <em>migrāš</em> (pastureland, common land around a Levitical city) is the technical term from Num 35:2-5 for the Levitical territories. <em>ʾăḥuzzāh</em> (possession, property) is the land-holding term of the Promised Land distribution. The Levites abandon their territorial claims in the north &mdash; a profound economic sacrifice &mdash; because Jeroboam had rejected them from being priests (<em>mikkahēn lĕKHWH</em>).</p>",
    "15": "<p>Jeroboam had appointed (<em>wayyaʿămēḏ</em>) his own priests for the high places (<em>labbāmôt</em>), for the goat demons (<em>laśśĕʿîrîm</em>), and for the calves (<em>lāʿĕgālîm</em>) that he had made. <em>śāʿîr</em> (goat, goat demon) appears in the prohibition of Lev 17:7 against &lsquo;sacrificing to goat demons&rsquo; &mdash; the same word used here. <em>ʿēgel</em> (calf) = the golden calves of Bethel and Dan (1 Kgs 12:28&ndash;29), recapitulating the Sinai apostasy. The Chronicler&rsquo;s characterization of the northern cult as demon-and-calf worship is polemical but uses the legal vocabulary of Lev 17&ndash;18.</p>",
    "16": "<p>&lsquo;And after the Levites, those from all the tribes of Israel who set their hearts (<em>nātnû ʾet-libbām</em>) to seek YHWH (<em>liḏrōš ʾet-YHWH</em>) came to Jerusalem.&rsquo; <em>nātan lēḇ</em> (to give/set the heart) = to devote oneself, commit intentionally. <em>dāraš</em> (to seek, inquire) is the Chronicler&rsquo;s central term for covenantal faithfulness: to seek YHWH is the opposite of forsaking him. The faithful remnant from all northern tribes self-selects by the criterion of seeking YHWH &mdash; the Chronicler&rsquo;s pan-Israel theology in miniature.</p>",
    "17": "<p>&lsquo;They strengthened (<em>yĕḥazzĕqû</em>) the kingdom of Judah and supported Rehoboam son of Solomon for three years.&rsquo; <em>ḥāzaq</em> (Piel) again &mdash; the migration of the faithful strengthens the Davidic kingdom precisely. The three-year period of obedience links to v17&rsquo;s explanation: &lsquo;for three years they walked in the way of David and Solomon&rsquo; (<em>hāleḵû bĕdereḵ dāwîḏ wĕšĕlōmōh</em>). The spatial metaphor of walking (<em>hālaḵ</em>) in the right way is Deuteronomic covenant language (Deut 5:33; 8:6).</p>",
    "18": "<p>Rehoboam took as wife Mahalath (<em>maḥălat</em>), daughter of Jerimoth son of David and of Abihail daughter of Eliab son of Jesse. The genealogy is complex: Mahalath&rsquo;s father Jerimoth is a son of David not mentioned in the main Davidic genealogy (1 Chr 3), suggesting a concubine-born son. Abihail her mother is granddaughter of Eliab, David&rsquo;s eldest brother (1 Sam 16:6). The marriage ties Rehoboam tightly to the Davidic and Eliadite lines &mdash; a strategic endogamous union.</p>",
    "19": "<p>She bore him sons: Jeush (<em>yeʿûš</em>), Shemariah (<em>šĕmaryāh</em>), and Zaham (<em>zaham</em>). Three sons from the first wife. The names: <em>yeʿûš</em> (possibly = &lsquo;let him help&rsquo; or related to <em>ʾûš</em>); <em>šĕmaryāh</em> = &lsquo;YHWH has preserved&rsquo;; <em>zaham</em> = perhaps &lsquo;loathing&rsquo; &mdash; an unusual name whose etymology is uncertain. The Chronicler preserves these names as part of the Davidic genealogical record, not because they play further narrative roles.</p>",
    "20": "<p>After Mahalath he took Maacah daughter of Absalom (<em>maʿăḵāh bat-ʾaḇšālôm</em>). Maacah is the daughter of Absalom &mdash; David&rsquo;s rebellious son. A son of Rehoboam marrying a granddaughter of Absalom&rsquo;s line is politically provocative, given Absalom&rsquo;s attempted usurpation of the throne. She bore him Abijah, Attai, Ziza, and Shelomith.</p>",
    "21": "<p>&lsquo;Rehoboam loved (<em>ʾāhēḇ</em>) Maacah daughter of Absalom more than all his wives and concubines.&rsquo; <em>ʾāhēḇ</em> (Qal perfect: loved) as marital/preferential attachment. The same verb is used of Isaac&rsquo;s preference for Esau in Gen 25:28 and Jacob&rsquo;s love for Rachel in Gen 29:18 &mdash; always preference that creates dynastic complications. &lsquo;He had 18 wives and 60 concubines, and fathered 28 sons and 60 daughters.&rsquo; The multiplication of wives and concubines violates Deut 17:17 (the king shall not &lsquo;multiply wives for himself&rsquo;); the Chronicler reports without editorial comment.</p>",
    "22": "<p>Rehoboam made Abijah (<em>ʾăḇîyāh</em>) the head (<em>lĕrōʾš</em>) above his brothers as prince-designate (<em>nāgîḏ</em>). <em>nāgîḏ</em> is the proto-kingship title used at key moments of dynastic designation: Saul (1 Sam 9:16), David (1 Sam 13:14; 2 Sam 6:21), and now Abijah. The appointment of Abijah despite Maacah&rsquo;s non-first-wife status is the royal prerogative, paralleling David&rsquo;s choice of Solomon over elder sons. The dynasty maintains the pattern of election-over-primogeniture.</p>",
    "23": "<p>Rehoboam &lsquo;acted wisely&rsquo; (<em>wayyāśeḵel</em>) in distributing his sons throughout the regions of Judah and Benjamin, to all the fortified cities, giving them abundant provisions and seeking many wives for them. <em>śāḵal</em> (Hiphil: to act wisely, be successful) is a wisdom-and-success verb (the same word as Joseph&rsquo;s success in Gen 39:3). Distributing princes to the fortified cities served both a defensive purpose (royal presence in the frontiers) and prevented court concentration of rival claimants. Seeking many wives for them parallels Rehoboam&rsquo;s own marriage politics.</p>"
  },
  "12": {
    "1": "<p>&lsquo;When the rule of Rehoboam was established (<em>wĕḵikôn malkût rĕḥaḇʿām</em>) and he was strong (<em>ûḵĕḥazzĕqātô</em>), he abandoned (<em>ʿāzaḇ</em>) the law of YHWH.&rsquo; The Chronicler&rsquo;s prosperity-apostasy pattern (cf. 2 Chr 17:6/12 → 17:19; 26:5 → 26:16): strength leads to self-reliance which leads to forsaking YHWH. <em>ʿāzaḇ</em> (to forsake, abandon) is the apostasy verb par excellence &mdash; the same word used of Israel forsaking YHWH (Judg 2:12; 2 Chr 15:2; 24:20). &lsquo;And all Israel with him&rsquo; (<em>wĕḵol-yiśrāʾēl ʿimmô</em>) &mdash; the king&rsquo;s apostasy implicates the whole community.</p>",
    "2": "<p>In the fifth year of King Rehoboam (<em>baššānāh haḥămîšît</em>), Shishak king of Egypt (<em>šîšaq melek-miṣrayim</em>) came up against Jerusalem. Historical synchronism: Pharaoh Sheshonq I (c. 945&ndash;924 BC) left an inscription at the temple of Karnak listing 150+ Palestinian cities he captured; the list includes sites in both Judah and Israel. Shishak&rsquo;s campaign is the first historically confirmable event of the divided monarchy period. &lsquo;Because they had been unfaithful to YHWH&rsquo; (<em>ʾăšer māʿălû bĕ-YHWH</em>) &mdash; <em>māʿal</em> (to act treacherously, commit sacrilege against) is the Chronicler&rsquo;s guilt-term for covenant violation.</p>",
    "3": "<p>Shishak came with 1,200 chariots, 60,000 horsemen, and innumerable troops: Libyans (<em>lûḇîm</em>), Sukkites (<em>sukkiyyîm</em>), and Cushites (<em>kûšîm</em>). <em>sukkiyyîm</em> appears only here in the OT &mdash; a hapax legomenon probably referring to Libyan auxiliary troops or a North African tribal group. <em>lûḇîm</em> (Libyans) and <em>kûšîm</em> (Cushites/Nubians) represent Egypt&rsquo;s multinational empire. The coalition&rsquo;s diversity emphasizes Egypt&rsquo;s imperial reach &mdash; and the magnitude of the threat against which Judah has no human defense.</p>",
    "4": "<p>He took (<em>wayyilkōḏ</em>) the fortified cities (<em>ʿārê hammaṣṣûrôt</em>) of Judah and came to Jerusalem. <em>lākaḏ</em> (to capture, seize) is the capture-of-cities vocabulary throughout Joshua and the Deuteronomistic history. The irony is precise: the very cities that Rehoboam had just fortified (ch11:5&ndash;12) fall to Shishak in his fifth year. The fortified defensive network built for security cannot withstand YHWH&rsquo;s judgment.</p>",
    "5": "<p>Shemaiah the prophet came to Rehoboam and the leaders of Judah who had gathered at Jerusalem. &lsquo;YHWH says: You have abandoned me (<em>ʿăzaḇtem ʾōtî</em>), so I have abandoned you to the hand of Shishak (<em>wĕgam-ʾănî ʿāzaḇtî ʾetḵem bĕyaḏ-šîšāq</em>).&rsquo; The talion structure is explicit: the same verb (<em>ʿāzaḇ</em>) is used for the people&rsquo;s action and YHWH&rsquo;s response. Forsaking produces forsaking. The divine lex talionis is a consistent pattern in the Chronicler&rsquo;s retributive theology.</p>",
    "6": "<p>&lsquo;The leaders of Israel and the king humbled themselves (<em>wayyikkānĕʿû śārê yiśrāʾēl wĕhammelek</em>) and said: YHWH is righteous (<em>ṣaddîq YHWH</em>).&rsquo; <em>kānaʿ</em> (Niphal: to humble oneself, be subdued) is the Chronicler&rsquo;s signature repentance verb, appearing in the famous conditional promise of 2 Chr 7:14 (&lsquo;if my people... humble themselves&rsquo;). Acknowledging &lsquo;YHWH is righteous&rsquo; (<em>ṣaddîq YHWH</em>) means accepting that the divine judgment is just, not arbitrary. The confession of divine righteousness in the face of punishment is the OT pattern of genuine repentance (Neh 9:33; Dan 9:14).</p>",
    "7": "<p>&lsquo;When YHWH saw (<em>wayyarʾ YHWH</em>) that they humbled themselves, the word of YHWH came to Shemaiah: They have humbled themselves (<em>niknaʿû</em>); I will not destroy them (<em>lōʾ ʾašḥîtēm</em>), but I will grant them some deliverance (<em>wĕnātattî lāhem kĕmĕʿaṭ lĕpālēṭāh</em>).&rsquo; <em>šāḥat</em> (Hiphil: to destroy, ruin) &mdash; the most severe punishment is averted. <em>kĕmĕʿaṭ</em> = a little, some (diminished amount); <em>pālēṭāh</em> = escape, deliverance. The partial deliverance formula signals the Chronicler&rsquo;s graduated response theology: full repentance yields full restoration; partial humbling yields partial relief.</p>",
    "8": "<p>&lsquo;But they will be his servants (<em>wĕhāyû-lô laʿăḇādîm</em>) so that they may know the difference between serving me and serving the kingdoms of the countries.&rsquo; The purpose clause is theological pedagogy: subjection to Shishak will teach what they failed to learn in freedom. <em>ʿāḇaḏ</em> (to serve, be a slave) applied both to serving YHWH (vocation) and serving Shishak (punishment). The distinction is: free people serve YHWH voluntarily; enslaved people serve foreign kings by compulsion. Sin converts vocation into servitude.</p>",
    "9": "<p>Shishak king of Egypt came up against Jerusalem and took (<em>wayyiqqaḥ</em>) the treasuries (<em>ʾōṣĕrôt</em>) of the house of YHWH and the treasuries of the king&rsquo;s house. He took everything, including the golden shields (<em>māginnê hazzāhāḇ</em>) that Solomon had made. The golden shields of 9:15-16, symbols of Solomonic peak glory, are now stripped away. The treasury-taking is a reversal: what the nations brought to Jerusalem under Solomon (9:24) now flows back out to the nations under Rehoboam.</p>",
    "10": "<p>King Rehoboam made in their place bronze shields (<em>māginnê nĕḥōšet</em>) and gave them in charge of the officers of the guard (<em>śārê hārāṣîm</em>). Bronze replaces gold: a visible, material demotion. The guard officers who carried the gold shields under Solomon now carry bronze substitutes. The degradation is architectural and economic: the temple precincts display a diminished glory corresponding to the diminished spiritual condition.</p>",
    "11": "<p>As often as the king entered the house of YHWH, the guard came and carried them, then brought them back to the guardroom (<em>liškat hārāṣîm</em>). The ceremonial function of the shields is preserved despite their material demotion. The ritual continues &mdash; the form without the substance &mdash; which may be the Chronicler&rsquo;s implicit critique: the appearance of worship maintained even after the gold of devotion has been stripped away.</p>",
    "12": "<p>&lsquo;Because he humbled himself (<em>šĕhiḵkānîʿa</em>), the wrath of YHWH (<em>ʾap YHWH</em>) turned away (<em>šāḇ</em>) from him and did not destroy him completely.&rsquo; <em>ʾap</em> (wrath, nostril) = YHWH&rsquo;s anger expressed in physical-emotional terms. <em>šûḇ</em> (to turn, return) applied to divine wrath: the turning-away of YHWH&rsquo;s face/anger is the reversal of the prophetic judgment. &lsquo;Indeed, there were good things in Judah (<em>ḵî gam-bîhûḏāh hāyû dĕḇārîm ṭôḇîm</em>).&rsquo; <em>ṭôḇ</em> (good) as the narrator&rsquo;s summary verdict: partial faithfulness yields a partial positive assessment.</p>",
    "13": "<p>King Rehoboam was strong (<em>wayyitḥazzēq</em>) in Jerusalem and reigned. He was 41 years old when he began to reign (<em>ben-ʾarbaʿîm wĕʾaḥat šānāh rĕḥaḇʿām bĕmolĕkô</em>) and reigned 17 years in Jerusalem. His mother was Naamah (<em>naʿămāh</em>) the Ammonitess. <em>naʿămāh</em> = pleasant, lovely (the same name as Naaman the Aramean general in 2 Kgs 5). Naamah&rsquo;s Ammonite origin is deliberately noted: Solomon&rsquo;s Deuteronomy-forbidden foreign wives (1 Kgs 11:1) have dynastic consequences &mdash; the divided kingdom is, in part, their theological legacy.</p>",
    "14": "<p>&lsquo;He did evil, because he did not set his heart (<em>lōʾ hēkîn lĕḇāḇô</em>) to seek YHWH.&rsquo; <em>kûn</em> (Hiphil: to establish, prepare, make firm) applied to the heart: <em>hēkîn lēḇ</em> = to prepare/establish the heart, the idiom for wholehearted devotion. David used this idiom positively (1 Chr 22:19: &lsquo;set your heart and soul to seek YHWH your God&rsquo;); Rehoboam fails it negatively. The &lsquo;prepared heart&rsquo; is the Chronicler&rsquo;s standard for Davidic faithfulness; its absence defines the failure of Rehoboam&rsquo;s reign.</p>",
    "15": "<p>The acts of Rehoboam, from first to last (<em>hāriʾšōnîm wĕhāʾaḥărōnîm</em>), are written in the records of Shemaiah the prophet and of Iddo the seer (<em>yĕʿaddô ḥōzeh</em>). <em>ḥōzeh</em> (seer) vs. <em>nāḇîʾ</em> (prophet): Shemaiah is called <em>nāḇîʾ</em> (v5) and Iddo is called <em>ḥōzeh</em> &mdash; the two prophetic modes. The citation of dual prophetic sources provides double witness for the regnal record. <em>mityaḥēś</em> (genealogical registration, Hithpael of <em>yāḥas</em>) also appears: there were wars between Rehoboam and Jeroboam throughout their reigns.</p>",
    "16": "<p>&lsquo;Rehoboam slept with his fathers (<em>wayyiškab rĕḥaḇʿām ʿim-ʾăḇōtāyw</em>) and was buried in the city of David. Abijah his son reigned in his place.&rsquo; The standard regnal death formula. Burial in &lsquo;the city of David&rsquo; maintains Rehoboam within the Davidic dynasty&rsquo;s sacred geography despite his faithlessness. The succession to Abijah &mdash; the son designated as <em>nāgîḏ</em> in 11:22 &mdash; confirms that Rehoboam&rsquo;s earlier dynastic planning succeeded even if his spiritual legacy failed.</p>"
  }
}

def main():
    data = load_comm('mkt-original', '2chronicles')
    merge_comm(data, CHRON2_ORIGINAL)
    save_comm('mkt-original', '2chronicles', data)
    total = sum(len(vs) for vs in CHRON2_ORIGINAL.values())
    print(f'2chronicles mkt-original ch 9-12: wrote {total} verses')

if __name__ == '__main__':
    main()
